"use client";

import React, { useState, useEffect, useRef } from "react";
import {
  Search,
  LineChart,
  AlertTriangle,
  TrendingUp,
  TrendingDown,
  Minus,
  RefreshCw,
  FileText,
  CheckCircle2,
  Activity,
  ShieldCheck,
  Layers,
  Sparkles,
} from "lucide-react";

// Types matching the API SSE output
interface StreamData {
  currentStep: string;
  logs: string[];
  queries: string[];
  verdict: "Bullish" | "Bearish" | "Neutral" | null;
  reasoningReport: string;
  revenueGrowthAnalysis: string;
  risksAnalysis: string;
  sentimentCompetitorsAnalysis: string;
  retryCount: number;
  verificationLog: string[];
  verificationPassed: boolean;
  error?: string;
}

export default function Home() {
  const [ticker, setTicker] = useState("");
  const [companyName, setCompanyName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Agent State
  const [currentStep, setCurrentStep] = useState<string>("");
  const [logs, setLogs] = useState<string[]>([]);
  const [queries, setQueries] = useState<string[]>([]);
  const [verdict, setVerdict] = useState<"Bullish" | "Bearish" | "Neutral" | null>(null);
  const [reasoningReport, setReasoningReport] = useState("");
  const [revenueGrowth, setRevenueGrowth] = useState("");
  const [risks, setRisks] = useState("");
  const [sentiment, setSentiment] = useState("");
  const [retryCount, setRetryCount] = useState(0);
  const [verificationLog, setVerificationLog] = useState<string[]>([]);
  const [verificationPassed, setVerificationPassed] = useState(false);

  const [activeTab, setActiveTab] = useState<"summary" | "revenue" | "risks" | "sentiment" | "verification">("summary");

  const terminalEndRef = useRef<HTMLDivElement>(null);

  // Auto scroll terminal logs
  useEffect(() => {
    if (terminalEndRef.current) {
      terminalEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [logs]);

  // Set active tab based on research completion
  useEffect(() => {
    if (verdict) {
      setActiveTab("summary");
    }
  }, [verdict]);

  const handleQuickSearch = (symbol: string, name: string) => {
    setTicker(symbol);
    setCompanyName(name);
  };

  const handleLaunchAgent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!ticker) return;

    // Reset previous state
    setLoading(true);
    setError(null);
    setCurrentStep("initiating");
    setLogs(["Launching AntiGravity Investment Agent...", "Awaiting LangGraph State Machine initialization..."]);
    setQueries([]);
    setVerdict(null);
    setReasoningReport("");
    setRevenueGrowth("");
    setRisks("");
    setSentiment("");
    setRetryCount(0);
    setVerificationLog([]);
    setVerificationPassed(false);

    try {
      const response = await fetch("/api/research", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          ticker: ticker.toUpperCase(),
          companyName,
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || "Failed to initiate research agent");
      }

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (!reader) {
        throw new Error("Failed to read server response stream");
      }

      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n\n");
        // Keep the last partial line in buffer
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (line.startsWith("data: ")) {
            const jsonStr = line.substring(6);
            try {
              const data = JSON.parse(jsonStr) as StreamData;

              if (data.error) {
                setError(data.error);
                setLogs((prev) => [...prev, `❌ Error: ${data.error}`]);
                setLoading(false);
                return;
              }

              // Update state elements based on streamed values
              if (data.currentStep) setCurrentStep(data.currentStep);
              if (data.retryCount !== undefined) setRetryCount(data.retryCount);
              if (data.verificationPassed !== undefined) setVerificationPassed(data.verificationPassed);

              if (data.logs && data.logs.length > 0) {
                // Ensure logs are accumulated nicely without duplication if we get full list
                setLogs(data.logs);
              }
              if (data.queries && data.queries.length > 0) {
                setQueries(data.queries);
              }
              if (data.verificationLog && data.verificationLog.length > 0) {
                setVerificationLog(data.verificationLog);
              }

              if (data.revenueGrowthAnalysis) setRevenueGrowth(data.revenueGrowthAnalysis);
              if (data.risksAnalysis) setRisks(data.risksAnalysis);
              if (data.sentimentCompetitorsAnalysis) setSentiment(data.sentimentCompetitorsAnalysis);
              if (data.verdict) setVerdict(data.verdict);
              if (data.reasoningReport) setReasoningReport(data.reasoningReport);

            } catch (err) {
              console.error("Failed to parse SSE data block", err);
            }
          }
        }
      }
    } catch (err: any) {
      console.error("Research error:", err);
      setError(err.message || "An unexpected error occurred");
      setLogs((prev) => [...prev, `❌ Fatal Error: ${err.message || "Operation failed"}`]);
    } finally {
      setLoading(false);
    }
  };

  // Safe manual markdown parser to display reports natively with Tailwind
  const renderMarkdown = (text: string) => {
    if (!text) return null;
    const lines = text.split("\n");

    const formatBoldText = (str: string) => {
      // Bold syntax **text**
      let formatted = str.replace(/\*\*(.*?)\*\*/g, '<strong class="text-white font-semibold">$1</strong>');
      // Inline code `code`
      formatted = formatted.replace(/`(.*?)`/g, '<code class="bg-gray-800 text-cyan-400 px-1 py-0.5 rounded font-mono text-xs">$1</code>');
      return formatted;
    };

    return (
      <div className="prose-report text-gray-300 text-sm leading-relaxed space-y-4">
        {lines.map((line, idx) => {
          const trimmed = line.trim();

          if (trimmed.startsWith("# ")) {
            return (
              <h1 key={idx} className="text-xl font-bold text-white border-b border-gray-850 pb-2 pt-4">
                {trimmed.replace("# ", "")}
              </h1>
            );
          }
          if (trimmed.startsWith("## ")) {
            return (
              <h2 key={idx} className="text-lg font-semibold text-gray-200 pt-3 border-b border-gray-900/50 pb-1">
                {trimmed.replace("## ", "")}
              </h2>
            );
          }
          if (trimmed.startsWith("### ")) {
            return (
              <h3 key={idx} className="text-md font-semibold text-cyan-400 pt-2">
                {trimmed.replace("### ", "")}
              </h3>
            );
          }
          if (trimmed.startsWith("- ") || trimmed.startsWith("* ")) {
            const content = trimmed.substring(2);
            return (
              <li
                key={idx}
                className="ml-6 list-disc mb-1"
                dangerouslySetInnerHTML={{ __html: formatBoldText(content) }}
              />
            );
          }
          if (trimmed.startsWith("> ")) {
            return (
              <blockquote
                key={idx}
                className="border-l-2 border-cyan-500 pl-4 py-1 italic bg-cyan-950/10 text-cyan-200 rounded-r my-2"
              >
                {trimmed.replace("> ", "")}
              </blockquote>
            );
          }
          if (trimmed === "") {
            return <div key={idx} className="h-1" />;
          }

          return (
            <p
              key={idx}
              dangerouslySetInnerHTML={{ __html: formatBoldText(line) }}
            />
          );
        })}
      </div>
    );
  };

  // Helpers to render active steps
  const getStepStatus = (stepKey: string) => {
    const stepsOrder = ["planning", "researching", "analyzing", "verifying", "synthesizing"];

    // Check validation specifically
    if (stepKey === "verifying") {
      if (currentStep === "verifying_failed") return "failed";
      if (currentStep === "verifying_passed") return "completed";
      if (currentStep === "analyzing" && currentStep !== "verifying") {
        // if we are analyzing, verification hasn't started
        return "idle";
      }
    }

    if (currentStep === stepKey) return "active";

    // Completed steps calculations
    const currentIndex = stepsOrder.indexOf(currentStep.replace("_passed", "").replace("_failed", ""));
    const targetIndex = stepsOrder.indexOf(stepKey);

    if (currentIndex > targetIndex) return "completed";
    if (verdict) return "completed"; // if we have verdict, everything completed

    return "idle";
  };

  return (
    <main className="min-h-screen py-10 px-4 md:px-8 max-w-6xl mx-auto flex flex-col justify-between">
      {/* Header */}
      <header className="text-center mb-8 flex flex-col items-center">
        <div className="flex items-center space-x-3 mb-2 animate-float">
          <div className="relative p-3 bg-gradient-to-br from-cyan-500 to-indigo-600 rounded-2xl shadow-lg glow-cyan border border-cyan-400/20">
            <Layers className="h-8 w-8 text-white" />
          </div>
          <h1 className="text-3xl font-extrabold tracking-tight bg-gradient-to-r from-white via-slate-200 to-cyan-400 bg-clip-text text-transparent">
            AntiGravity AI
          </h1>
        </div>
        <p className="text-slate-400 text-sm max-w-md">
          Autonomous cyclic LangGraph research agent delivering market-defying investment intelligence.
        </p>
      </header>

      {/* Inputs Form */}
      <section className="glass-panel rounded-2xl p-6 glow-cyan mb-8 border border-white/5">
        <form onSubmit={handleLaunchAgent} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex flex-col space-y-1">
              <label htmlFor="ticker" className="text-xs font-semibold text-slate-400 tracking-wider uppercase">
                Ticker Symbol *
              </label>
              <div className="relative">
                <Search className="absolute left-3 top-3.5 h-4 w-4 text-slate-500" />
                <input
                  id="ticker"
                  type="text"
                  placeholder="e.g. NVDA, TSLA, AAPL"
                  required
                  value={ticker}
                  onChange={(e) => setTicker(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 bg-slate-950/80 border border-slate-800 rounded-xl text-white placeholder-slate-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all text-sm font-medium uppercase"
                />
              </div>
            </div>
            <div className="flex flex-col space-y-1">
              <label htmlFor="companyName" className="text-xs font-semibold text-slate-400 tracking-wider uppercase">
                Company Name (Optional)
              </label>
              <input
                id="companyName"
                type="text"
                placeholder="e.g. NVIDIA Corporation"
                value={companyName}
                onChange={(e) => setCompanyName(e.target.value)}
                className="w-full px-4 py-3 bg-slate-950/80 border border-slate-800 rounded-xl text-white placeholder-slate-600 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 transition-all text-sm font-medium"
              />
            </div>
          </div>

          <div className="flex flex-wrap gap-2 pt-2 items-center justify-between">
            <div className="flex flex-wrap gap-1.5 items-center">
              <span className="text-xs text-slate-500 mr-1.5">Examples:</span>
              <button
                type="button"
                onClick={() => handleQuickSearch("NVDA", "NVIDIA Corporation")}
                className="px-2.5 py-1 bg-slate-900 hover:bg-slate-850 border border-slate-800 hover:border-slate-700 text-xs rounded-lg text-slate-450 hover:text-cyan-400 transition-all cursor-pointer font-mono"
              >
                NVDA
              </button>
              <button
                type="button"
                onClick={() => handleQuickSearch("TSLA", "Tesla Inc")}
                className="px-2.5 py-1 bg-slate-900 hover:bg-slate-850 border border-slate-800 hover:border-slate-700 text-xs rounded-lg text-slate-450 hover:text-cyan-400 transition-all cursor-pointer font-mono"
              >
                TSLA
              </button>
              <button
                type="button"
                onClick={() => handleQuickSearch("AAPL", "Apple Inc")}
                className="px-2.5 py-1 bg-slate-900 hover:bg-slate-850 border border-slate-800 hover:border-slate-700 text-xs rounded-lg text-slate-450 hover:text-cyan-400 transition-all cursor-pointer font-mono"
              >
                AAPL
              </button>
              <button
                type="button"
                onClick={() => handleQuickSearch("MSFT", "Microsoft Corp")}
                className="px-2.5 py-1 bg-slate-900 hover:bg-slate-850 border border-slate-800 hover:border-slate-700 text-xs rounded-lg text-slate-450 hover:text-cyan-400 transition-all cursor-pointer font-mono"
              >
                MSFT
              </button>
            </div>

            <button
              type="submit"
              disabled={loading || !ticker}
              className={`px-6 py-3 bg-gradient-to-r from-cyan-500 to-indigo-600 hover:from-cyan-400 hover:to-indigo-500 text-white font-semibold rounded-xl text-sm transition-all shadow-md cursor-pointer flex items-center space-x-2 ${
                loading ? "opacity-60 cursor-not-allowed" : "hover:-translate-y-0.5 active:translate-y-0"
              }`}
            >
              {loading ? (
                <>
                  <RefreshCw className="h-4 w-4 animate-spin" />
                  <span>Agent Working...</span>
                </>
              ) : (
                <>
                  <Sparkles className="h-4 w-4" />
                  <span>Initiate Research Loop</span>
                </>
              )}
            </button>
          </div>
        </form>
      </section>

      {/* Error Message */}
      {error && (
        <div className="glass-panel border-red-500/20 bg-red-950/20 rounded-xl p-4 text-red-300 text-sm flex items-center space-x-3 mb-8">
          <AlertTriangle className="h-5 w-5 text-red-500 shrink-0" />
          <span>{error}</span>
        </div>
      )}

      {/* Main Grid View */}
      {(loading || verdict || logs.length > 0) && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
          {/* Left panel: Pipeline Visualization & Terminal Logs */}
          <div className="lg:col-span-1 space-y-6">
            {/* LangGraph Pipeline Viz */}
            <div className="glass-panel rounded-2xl p-5 border border-white/5">
              <h2 className="text-sm font-semibold text-slate-350 tracking-wider uppercase mb-4 flex items-center space-x-2">
                <Activity className="h-4 w-4 text-cyan-400" />
                <span>LangGraph Workflow</span>
              </h2>

              <div className="relative pl-6 space-y-5">
                {/* Visual Connector Line */}
                <div className="absolute left-[11px] top-2 bottom-2 w-0.5 bg-slate-800" />

                {/* Node 1: Query Planner */}
                <div className="relative flex items-start space-x-3">
                  <div
                    className={`absolute -left-[20px] h-[10px] w-[10px] rounded-full border-2 ${
                      getStepStatus("planning") === "completed"
                        ? "bg-cyan-500 border-cyan-450"
                        : getStepStatus("planning") === "active"
                        ? "bg-slate-900 border-cyan-400 animate-pulse-fast"
                        : "bg-slate-950 border-slate-800"
                    }`}
                  />
                  <div>
                    <h3 className={`text-xs font-semibold ${getStepStatus("planning") === "active" ? "text-cyan-400" : "text-slate-300"}`}>
                      1. Query Planner Node
                    </h3>
                    <p className="text-[10px] text-slate-500">Formulating targeted web queries</p>
                  </div>
                </div>

                {/* Node 2: Search Executor */}
                <div className="relative flex items-start space-x-3">
                  <div
                    className={`absolute -left-[20px] h-[10px] w-[10px] rounded-full border-2 ${
                      getStepStatus("researching") === "completed"
                        ? "bg-cyan-500 border-cyan-450"
                        : getStepStatus("researching") === "active"
                        ? "bg-slate-900 border-cyan-400 animate-pulse-fast"
