                      getStepStatus("verifying") === "completed"
                        ? "bg-emerald-500 border-emerald-450"
                        : getStepStatus("verifying") === "failed"
                        ? "bg-red-500 border-red-400 animate-bounce"
                        : getStepStatus("verifying") === "active"
                        ? "bg-slate-900 border-amber-400 animate-pulse-fast"
                        : "bg-slate-950 border-slate-800"
                    }`}
                  />
                  <div className="w-full">
                    <div className="flex items-center justify-between">
                      <h3
                        className={`text-xs font-semibold ${
                          getStepStatus("verifying") === "active"
                            ? "text-amber-400"
                            : getStepStatus("verifying") === "failed"
                            ? "text-red-400"
                            : getStepStatus("verifying") === "completed"
                            ? "text-emerald-400"
                            : "text-slate-300"
                        }`}
                      >
                        4. Fact verification Audit
                      </h3>
                      {retryCount > 0 && (
                        <span className="text-[9px] px-1.5 py-0.5 bg-red-950/30 border border-red-900/30 text-red-400 rounded-md font-mono">
                          Loop Retry #{retryCount}
                        </span>
                      )}
                    </div>
                    <p className="text-[10px] text-slate-500">Checking data integrity & late 2025/2026 coverage</p>
                  </div>
                </div>

                {/* Node 5: Report Synthesis */}
                <div className="relative flex items-start space-x-3">
                  <div
                    className={`absolute -left-[20px] h-[10px] w-[10px] rounded-full border-2 ${
                      getStepStatus("synthesizing") === "completed"
                        ? "bg-cyan-500 border-cyan-450"
                        : getStepStatus("synthesizing") === "active"
                        ? "bg-slate-900 border-cyan-400 animate-pulse-fast"
                        : "bg-slate-950 border-slate-800"
                    }`}
                  />
                  <div>
                    <h3 className={`text-xs font-semibold ${getStepStatus("synthesizing") === "active" ? "text-cyan-400" : "text-slate-300"}`}>
