                      <TrendingDown className="h-8 w-8 text-rose-400" />
                    ) : (
                      <Minus className="h-8 w-8 text-amber-400" />
                    )}
                  </div>
                </div>

                {/* Mini metrics bar */}
                <div className="mt-5 grid grid-cols-3 gap-4 border-t border-white/5 pt-4">
                  <div>
                    <span className="text-[10px] text-slate-500 block uppercase font-medium">Confidence</span>
                    <span className="text-sm font-semibold text-white">High</span>
                  </div>
