                    <span className="text-sm font-semibold text-white">
                      {retryCount > 0 ? `${retryCount} Retries` : "Passed Clean"}
                    </span>
                  </div>
                </div>
              </div>
            )}

            {/* Analysis Report View Tabs */}
            <div className="glass-panel rounded-2xl border border-white/5 overflow-hidden flex flex-col min-h-[400px]">
              {/* Navigation Tabs */}
              <div className="flex border-b border-white/5 bg-slate-900/40 overflow-x-auto">
                <button
                  onClick={() => setActiveTab("summary")}
                  disabled={!verdict}
                  className={`px-5 py-3.5 text-xs font-semibold border-b-2 tracking-wide transition-all whitespace-nowrap cursor-pointer ${
                    activeTab === "summary"
                      ? "border-cyan-500 text-cyan-400 bg-slate-900/60"
                      : "border-transparent text-slate-400 hover:text-slate-200"
                  } ${!verdict ? "opacity-40 cursor-not-allowed" : ""}`}
                >
                  <div className="flex items-center space-x-1.5">
                    <FileText className="h-3.5 w-3.5" />
                    <span>Thesis Report</span>
                  </div>
                </button>

                <button
                  onClick={() => setActiveTab("revenue")}
                  disabled={!revenueGrowth}
                  className={`px-5 py-3.5 text-xs font-semibold border-b-2 tracking-wide transition-all whitespace-nowrap cursor-pointer ${
                    activeTab === "revenue"
                      ? "border-cyan-500 text-cyan-400 bg-slate-900/60"
                      : "border-transparent text-slate-400 hover:text-slate-200"
                  } ${!revenueGrowth ? "opacity-40 cursor-not-allowed" : ""}`}
                >
                  <div className="flex items-center space-x-1.5">
                    <LineChart className="h-3.5 w-3.5" />
                    <span>Revenue & Growth</span>
                  </div>
                </button>

                <button
                  onClick={() => setActiveTab("risks")}
                  disabled={!risks}
                  className={`px-5 py-3.5 text-xs font-semibold border-b-2 tracking-wide transition-all whitespace-nowrap cursor-pointer ${
                    activeTab === "risks"
                      ? "border-cyan-500 text-cyan-400 bg-slate-900/60"
                      : "border-transparent text-slate-400 hover:text-slate-200"
                  } ${!risks ? "opacity-40 cursor-not-allowed" : ""}`}
                >
                  <div className="flex items-center space-x-1.5">
                    <AlertTriangle className="h-3.5 w-3.5" />
                    <span>Risk Factors</span>
                  </div>
                </button>

                <button
                  onClick={() => setActiveTab("sentiment")}
                  disabled={!sentiment}
                  className={`px-5 py-3.5 text-xs font-semibold border-b-2 tracking-wide transition-all whitespace-nowrap cursor-pointer ${
                    activeTab === "sentiment"
                      ? "border-cyan-500 text-cyan-400 bg-slate-900/60"
                      : "border-transparent text-slate-400 hover:text-slate-200"
                  } ${!sentiment ? "opacity-40 cursor-not-allowed" : ""}`}
                >
                  <div className="flex items-center space-x-1.5">
                    <ShieldCheck className="h-3.5 w-3.5" />
                    <span>Landscape & Sentiment</span>
                  </div>
                </button>

                <button
                  onClick={() => setActiveTab("verification")}
                  disabled={verificationLog.length === 0 && !verificationPassed}
                  className={`px-5 py-3.5 text-xs font-semibold border-b-2 tracking-wide transition-all whitespace-nowrap cursor-pointer ${
                    activeTab === "verification"
                      ? "border-cyan-500 text-cyan-400 bg-slate-900/60"
                      : "border-transparent text-slate-400 hover:text-slate-200"
                  } ${verificationLog.length === 0 && !verificationPassed ? "opacity-40 cursor-not-allowed" : ""}`}
                >
                  <div className="flex items-center space-x-1.5">
                    <CheckCircle2 className="h-3.5 w-3.5" />
                    <span>Verification Log</span>
                  </div>
                </button>
              </div>

              {/* Tab Content Area */}
              <div className="p-6 flex-1 overflow-y-auto max-h-[500px]">
                {/* 1. Thesis Summary */}
                {activeTab === "summary" && verdict && (
                  <div className="space-y-4">
                    {renderMarkdown(reasoningReport)}
                  </div>
                )}

                {/* 2. Revenue & Growth */}
                {activeTab === "revenue" && revenueGrowth && (
                  <div className="space-y-4">
                    <h2 className="text-base font-bold text-white mb-2 flex items-center space-x-2">
                      <LineChart className="h-4 w-4 text-cyan-400" />
                      <span>Revenue, Margins and Financial Trajectory</span>
                    </h2>
                    {renderMarkdown(revenueGrowth)}
                  </div>
                )}

                {/* 3. Risks */}
                {activeTab === "risks" && risks && (
                  <div className="space-y-4">
                    <h2 className="text-base font-bold text-white mb-2 flex items-center space-x-2">
                      <AlertTriangle className="h-4 w-4 text-rose-400" />
                      <span>SEC Risk Disclosures & Headwinds</span>
                    </h2>
                    {renderMarkdown(risks)}
                  </div>
                )}

                {/* 4. Competitors & Sentiment */}
                {activeTab === "sentiment" && sentiment && (
                  <div className="space-y-4">
                    <h2 className="text-base font-bold text-white mb-2 flex items-center space-x-2">
                      <ShieldCheck className="h-4 w-4 text-indigo-400" />
                      <span>Competitive Landscape & Market Headlines</span>
                    </h2>
                    {renderMarkdown(sentiment)}
                  </div>
                )}

                {/* 5. Verification Log Details */}
                {activeTab === "verification" && (
                  <div className="space-y-4">
                    <h2 className="text-base font-bold text-white mb-3 flex items-center space-x-2">
                      <CheckCircle2 className="h-4 w-4 text-emerald-400" />
                      <span>Data Integrity Audit Log</span>
                    </h2>

                    {verificationPassed && (
                      <div className="p-4 bg-emerald-950/20 border border-emerald-500/20 text-emerald-300 text-xs rounded-xl flex items-start space-x-2.5 mb-4">
                        <CheckCircle2 className="h-4 w-4 text-emerald-400 shrink-0 mt-0.5" />
                        <div>
                          <p className="font-semibold text-white">Audit Checklist Passed</p>
                          <p className="mt-1 text-slate-400 leading-relaxed">
                            No critical data discrepancies, temporal gaps, or competitor omissions were flagged. The gathered information satisfies the 2026 temporal and financial accuracy verification tests.
                          </p>
                        </div>
                      </div>
                    )}

                    {verificationLog.length > 0 && (
                      <div className="space-y-3">
                        <p className="text-xs text-slate-400">
                          The following issues/gaps were detected by the Audit Node during evaluation. Gaps trigger a search refinement recursion.
                        </p>
                        <div className="space-y-2">
                          {verificationLog.map((err, i) => (
                            <div
                              key={i}
                              className="p-3 bg-red-950/10 border border-red-500/10 text-red-300 rounded-xl text-xs flex items-start space-x-2"
                            >
                              <AlertTriangle className="h-3.5 w-3.5 text-red-400 shrink-0 mt-0.5" />
                              <span>{err}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                )}

                {/* Idle/Loading Initial State message */}
                {!verdict && !loading && (
                  <div className="h-full flex flex-col items-center justify-center text-center text-slate-500 py-16">
                    <Layers className="h-12 w-12 text-slate-700 mb-3 animate-pulse" />
                    <h3 className="text-sm font-semibold text-slate-400">Awaiting Agent Input</h3>
                    <p className="text-xs text-slate-600 max-w-xs mt-1">
                      Enter a ticker symbol above to start the cyclic research state machine.
                    </p>
                  </div>
                )}

                {/* Active Loading but no verdict yet */}
                {!verdict && loading && (
                  <div className="h-full flex flex-col items-center justify-center text-center text-slate-400 py-16 space-y-4">
                    <RefreshCw className="h-10 w-10 text-cyan-400 animate-spin" />
                    <div>
                      <h3 className="text-sm font-semibold text-slate-300">
                        {currentStep === "planning"
                          ? "Planning queries..."
                          : currentStep === "researching"
                          ? "Executing web searches..."
                          : currentStep === "analyzing"
                          ? "Evaluating pillars..."
                          : currentStep.startsWith("verifying")
                          ? "Auditing facts..."
                          : currentStep === "synthesizing"
                          ? "Compiling thesis report..."
                          : "Initializing agent loops..."}
                      </h3>
                      <p className="text-xs text-slate-500 mt-1">
                        Please wait. The agent verifies its findings in a LangGraph loop.
                      </p>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}

