import { NextRequest } from "next/server";
import { agent } from "@/lib/agent";

export const runtime = "nodejs";

export async function POST(req: NextRequest) {
  try {
    const { ticker, companyName, demo } = await req.json();

    if (!ticker) {
      return new Response(JSON.stringify({ error: "Ticker symbol is required" }), {
        status: 400,
        headers: { "Content-Type": "application/json" },
      });
    }

    const encoder = new TextEncoder();

    // If demo is true, run a fully simulated agent workflow with delays
    if (demo === true) {
      const stream = new ReadableStream({
        async start(controller) {
          try {
            await runMockStream(ticker.toUpperCase().trim(), companyName || "", controller, encoder);
            controller.close();
          } catch (err: any) {
            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ error: err.message })}\n\n`));
            controller.close();
          }
        },
      });

      return new Response(stream, {
        headers: {
          "Content-Type": "text/event-stream",
          "Cache-Control": "no-cache, no-transform",
          "Connection": "keep-alive",
        },
      });
    }

    // Otherwise, check for required API keys
    if (!process.env.TAVILY_API_KEY) {
      return new Response(
        JSON.stringify({
          error: "TAVILY_API_KEY is not configured in `.env.local`. Please configure it OR check the 'Demo Mode' box to run a simulation.",
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    if (!process.env.OPENAI_API_KEY && !process.env.GEMINI_API_KEY) {
      return new Response(
        JSON.stringify({
          error: "Neither OPENAI_API_KEY nor GEMINI_API_KEY is configured in `.env.local`. Please provide one OR check 'Demo Mode' to simulate.",
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    const stream = new ReadableStream({
      async start(controller) {
        try {
          const agentStream = await agent.stream(
            {
              ticker: ticker.toUpperCase().trim(),
              companyName: companyName ? companyName.trim() : "",
            },
            {
              streamMode: "values",
            }
          );

          for await (const chunk of agentStream) {
            const data = {
              currentStep: chunk.currentStep,
              logs: chunk.logs || [],
              queries: chunk.queries || [],
              verdict: chunk.verdict,
              reasoningReport: chunk.reasoningReport,
              revenueGrowthAnalysis: chunk.revenueGrowthAnalysis,
              risksAnalysis: chunk.risksAnalysis,
              sentimentCompetitorsAnalysis: chunk.sentimentCompetitorsAnalysis,
              retryCount: chunk.retryCount || 0,
              verificationLog: chunk.verificationLog || [],
              verificationPassed: chunk.verificationPassed || false,
            };

            controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
          }
          controller.close();
        } catch (err: any) {
          console.error("Agent Streaming Error:", err);
          controller.enqueue(
            encoder.encode(
              `data: ${JSON.stringify({
                error: err.message || "An unexpected error occurred during research loop",
              })}\n\n`
            )
          );
          controller.close();
        }
      },
    });

    return new Response(stream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache, no-transform",
        "Connection": "keep-alive",
      },
    });
  } catch (error: any) {
    console.error("API Route Error:", error);
    return new Response(JSON.stringify({ error: error.message || "Invalid request body" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }
}

