Quarterly results show revenue of $26.8B (18% growth YoY), driven by premium product pricing and services expansion. Gross margins stand at 74.2% (up 140bps), outclassing peers. Forward growth remains strong at 15-20%.

## Risk Profile
Key concerns include supply chain reliance on key single-source vendors, regulatory hurdles in European jurisdictions, and potential capex softening under tight interest rate environments.

## Competitive Landscape
Maintains a solid 62% market share over secondary competitors. Technological advantages in hardware and software integrations create a wide economic moat that rivals struggle to challenge.

## Investment Verdict & Catalysts
- **Verdict**: **${verdict}**
- **Bull Catalysts**: Continued enterprise cloud adoption, product launches, margin expansion.
- **Bear Catalysts**: Supply bottleneck delays, geopolitical friction affecting exports.`;

  // Persist demo report to database too, so that demo runs get stored!
  try {
    await prisma.researchReport.create({
      data: {
        ticker: ticker.toUpperCase().trim(),
        companyName: resolvedName,
        verdict,
        safetyScore,
        reasoningReport,
        revenueAnalysis: `### Revenue & Growth Analysis (${ticker})\n- **Recent Earnings**: Reported revenue of $26.8B (up 18% YoY) for the latest quarter ending early 2026.\n- **Gross Margins**: Consolidated gross margins increased to 74.2%.\n- **Guidance**: Management projects 15-20% growth.`,
        risksAnalysis: `### Risks & Headwinds\n- **Supply Chain**: Reliance on specific semiconductor fabricators.\n- **Regulatory Pressure**: Ongoing antitrust scrutiny in key European markets.`,
        sentimentAnalysis: `### Competitor & Market Sentiment\n- **Market Share**: Maintained leading market share (~62%).\n- **Analyst Coverage**: 14 of 16 top analysts maintain 'Buy' ratings.`,
        strategyHorizon: horizon,
        strategyRisk: risk,
      },
    });
  } catch (dbErr) {
    console.error("Database save failed (Demo):", dbErr);
  }

  controller.enqueue(
    encoder.encode(
      `data: ${JSON.stringify({
        currentStep: "synthesizing",
        verdict,
        safetyScore,
        safetyBreakdown: JSON.stringify(mockBreakdown),
        reasoningReport,
        logs: [
          `[DEMO MODE] Executed Python quantitative engine: computed Safety Index = ${safetyScore}/100.`,
          `[DEMO MODE] Synthesized final verdict: "${verdict.toUpperCase()}"`,
          `[DEMO MODE] Saved report to database.`,
          `[DEMO MODE] Agent pipeline finished execution.`,
        ],
      })}\n\n`
    )
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import {
  Search,
  LineChart,
  AlertTriangle,
  TrendingUp,
  TrendingDown,
  Minus,
  RefreshCw,
  FileText,
  CheckCircle2,
  Activity,
  ShieldCheck,
  Layers,
  Sparkles,
  Sliders,
  History,
  SlidersHorizontal,
} from "lucide-react";

// Types matching the API SSE output
interface StreamData {
  currentStep: string;
  logs: string[];
  queries: string[];
  verdict: "Bullish" | "Bearish" | "Neutral" | null;
  safetyScore: number;
  safetyBreakdown: string;
  reasoningReport: string;
  revenueGrowthAnalysis: string;
  risksAnalysis: string;
  sentimentCompetitorsAnalysis: string;
  retryCount: number;
  verificationLog: string[];
  verificationPassed: boolean;
  error?: string;
}

// Type matching past reports retrieved from database
interface PastReport {
  id: string;
  ticker: string;
  companyName: string;
  verdict: "Bullish" | "Bearish" | "Neutral";
  safetyScore: number;
  reasoningReport: string;
  revenueAnalysis: string;
  risksAnalysis: string;
  sentimentAnalysis: string;
  strategyHorizon: string;
  strategyRisk: string;
  createdAt: string;
}

export default function Home() {
  const [ticker, setTicker] = useState("");
  const [companyName, setCompanyName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [demo, setDemo] = useState(true);

  // Strategy Profiler State
  const [strategyHorizon, setStrategyHorizon] = useState("Medium-Term");
  const [strategyRisk, setStrategyRisk] = useState("Balanced");
  const [revenueWeight, setRevenueWeight] = useState(33);
  const [riskWeight, setRiskWeight] = useState(33);
  const [sentimentWeight, setSentimentWeight] = useState(34);

  // Agent State
  const [currentStep, setCurrentStep] = useState<string>("");
  const [logs, setLogs] = useState<string[]>([]);
  const [queries, setQueries] = useState<string[]>([]);
  const [verdict, setVerdict] = useState<"Bullish" | "Bearish" | "Neutral" | null>(null);
  const [safetyScore, setSafetyScore] = useState(0);
  const [safetyBreakdown, setSafetyBreakdown] = useState<any>({});
  const [reasoningReport, setReasoningReport] = useState("");
  const [revenueGrowth, setRevenueGrowth] = useState("");
  const [risks, setRisks] = useState("");
  const [sentiment, setSentiment] = useState("");
  const [retryCount, setRetryCount] = useState(0);
  const [verificationLog, setVerificationLog] = useState<string[]>([]);
  const [verificationPassed, setVerificationPassed] = useState(false);

  // Navigation and Database History
  const [activeTab, setActiveTab] = useState<"summary" | "revenue" | "risks" | "sentiment" | "verification">("summary");
  const [pastReports, setPastReports] = useState<PastReport[]>([]);

  const terminalEndRef = useRef<HTMLDivElement>(null);

  // Fetch History from database on mount
  const fetchHistory = async () => {
    try {
      const res = await fetch("/api/research");
      if (res.ok) {
        const data = await res.json();
        setPastReports(data);
      }
    } catch (e) {
      console.error("Failed to load history:", e);
    }
  };

  useEffect(() => {
    fetchHistory();
  }, []);

  // Auto scroll terminal logs
  useEffect(() => {
    if (terminalEndRef.current) {
      terminalEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [logs]);

  // Set active tab based on research completion
  useEffect(() => {
    if (verdict) {
      setActiveTab("summary");
    }
  }, [verdict]);

  // Proportional weight adjustments (Total sums to 100%)
  const handleWeightChange = (type: "revenue" | "risk" | "sentiment", value: number) => {
    const remaining = 100 - value;
    if (type === "revenue") {
      const totalOther = riskWeight + sentimentWeight;
      if (totalOther === 0) {
        setRiskWeight(Math.round(remaining / 2));
        setSentimentWeight(Math.round(remaining / 2));
      } else {
        setRiskWeight(Math.round((riskWeight / totalOther) * remaining));
        setSentimentWeight(100 - value - Math.round((riskWeight / totalOther) * remaining));
      }
      setRevenueWeight(value);
    } else if (type === "risk") {
      const totalOther = revenueWeight + sentimentWeight;
      if (totalOther === 0) {
        setRevenueWeight(Math.round(remaining / 2));
        setSentimentWeight(Math.round(remaining / 2));
      } else {
        setRevenueWeight(Math.round((revenueWeight / totalOther) * remaining));
        setSentimentWeight(100 - value - Math.round((revenueWeight / totalOther) * remaining));
      }
      setRiskWeight(value);
    } else {
      const totalOther = revenueWeight + riskWeight;
      if (totalOther === 0) {
        setRevenueWeight(Math.round(remaining / 2));
        setRiskWeight(Math.round(remaining / 2));
      } else {
        setRevenueWeight(Math.round((revenueWeight / totalOther) * remaining));
        setRiskWeight(100 - value - Math.round((revenueWeight / totalOther) * remaining));
      }
      setSentimentWeight(value);
    }
  };

  const handleQuickSearch = (symbol: string, name: string) => {
    setTicker(symbol);
    setCompanyName(name);
  };

  const loadPastReport = (report: PastReport) => {
    setTicker(report.ticker);
    setCompanyName(report.companyName);
    setVerdict(report.verdict);
    setSafetyScore(report.safetyScore);
    setReasoningReport(report.reasoningReport);
    setRevenueGrowth(report.revenueAnalysis);
    setRisks(report.risksAnalysis);
    setSentiment(report.sentimentAnalysis);
    setStrategyHorizon(report.strategyHorizon);
    setStrategyRisk(report.strategyRisk);
    setVerificationPassed(true);
    setVerificationLog([]);
    setRetryCount(0);
    setCurrentStep("synthesizing");
    setLogs([
      `[DATABASE] Loaded historical report for ${report.ticker} (${report.companyName})`,
      `[DATABASE] Created on: ${new Date(report.createdAt).toLocaleString()}`,
    ]);
  };

  const handleLaunchAgent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!ticker) return;

    // Reset previous state
    setLoading(true);
    setError(null);
    setCurrentStep("initiating");
    setLogs(["Launching AntiGravity Investment Agent...", "Awaiting LangGraph State Machine initialization..."]);
    setQueries([]);
    setVerdict(null);
    setSafetyScore(0);
    setSafetyBreakdown({});
    setReasoningReport("");
    setRevenueGrowth("");
    setRisks("");
    setSentiment("");
    setRetryCount(0);
    setVerificationLog([]);
    setVerificationPassed(false);

    try {
      const response = await fetch("/api/research", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          ticker: ticker.toUpperCase(),
          companyName,
          demo,
          strategyHorizon,
          strategyRisk,
          revenueWeight,
          riskWeight,
          sentimentWeight,
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || "Failed to initiate research agent");
      }

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (!reader) {
        throw new Error("Failed to read server response stream");
      }

      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n\n");
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (line.startsWith("data: ")) {
            const jsonStr = line.substring(6);
            try {
              const data = JSON.parse(jsonStr) as StreamData;

              if (data.error) {
                setError(data.error);
                setLogs((prev) => [...prev, `❌ Error: ${data.error}`]);
                setLoading(false);
                return;
              }

              if (data.currentStep) setCurrentStep(data.currentStep);
              if (data.retryCount !== undefined) setRetryCount(data.retryCount);
              if (data.verificationPassed !== undefined) setVerificationPassed(data.verificationPassed);

              if (data.logs && data.logs.length > 0) {
                setLogs(data.logs);
              }
              if (data.queries && data.queries.length > 0) {
                setQueries(data.queries);
              }
              if (data.verificationLog && data.verificationLog.length > 0) {
                setVerificationLog(data.verificationLog);
              }

              if (data.revenueGrowthAnalysis) setRevenueGrowth(data.revenueGrowthAnalysis);
              if (data.risksAnalysis) setRisks(data.risksAnalysis);
              if (data.sentimentCompetitorsAnalysis) setSentiment(data.sentimentCompetitorsAnalysis);
              if (data.verdict) setVerdict(data.verdict);
              if (data.safetyScore) setSafetyScore(data.safetyScore);
              if (data.safetyBreakdown) {
                try {
                  setSafetyBreakdown(JSON.parse(data.safetyBreakdown));
                } catch {
                  setSafetyBreakdown({});
                }
              }
              if (data.reasoningReport) setReasoningReport(data.reasoningReport);
            } catch (err) {
              console.error("Failed to parse SSE data block", err);
            }
          }
        }
      }

      // Refresh DB history list when a run completes
      fetchHistory();
    } catch (err: any) {
      console.error("Research error:", err);
      setError(err.message || "An unexpected error occurred");
      setLogs((prev) => [...prev, `❌ Fatal Error: ${err.message || "Operation failed"}`]);
    } finally {
      setLoading(false);
    }
  };

  const renderMarkdown = (text: string) => {
    if (!text) return null;
    const lines = text.split("\n");

    const formatBoldText = (str: string) => {
      let formatted = str.replace(/\*\*(.*?)\*\*/g, '<strong class="text-white font-semibold">$1</strong>');
      formatted = formatted.replace(
        /`(.*?)`/g,
        '<code class="bg-gray-800 text-cyan-400 px-1 py-0.5 rounded font-mono text-xs">$1</code>'
      );
      return formatted;
    };

    return (
      <div className="prose-report text-gray-305 text-sm leading-relaxed space-y-4">
        {lines.map((line, idx) => {
          const trimmed = line.trim();

          if (trimmed.startsWith("# ")) {
            return (
              <h1 key={idx} className="text-xl font-bold text-white border-b border-gray-850 pb-2 pt-4">
                {trimmed.replace("# ", "")}
              </h1>
            );
          }
          if (trimmed.startsWith("## ")) {
            return (
              <h2 key={idx} className="text-lg font-semibold text-gray-200 pt-3 border-b border-gray-900/50 pb-1">
                {trimmed.replace("## ", "")}
              </h2>
            );
          }
          if (trimmed.startsWith("### ")) {
            return (
              <h3 key={idx} className="text-md font-semibold text-cyan-400 pt-2">
                {trimmed.replace("### ", "")}
              </h3>
            );
          }
          if (trimmed.startsWith("- ") || trimmed.startsWith("* ")) {
            const content = trimmed.substring(2);
            return (
              <li
                key={idx}
                className="ml-6 list-disc mb-1"
                dangerouslySetInnerHTML={{ __html: formatBoldText(content) }}
              />
            );
          }
          if (trimmed.startsWith("> ")) {
            return (
              <blockquote
                key={idx}
                className="border-l-2 border-cyan-500 pl-4 py-1 italic bg-cyan-950/10 text-cyan-200 rounded-r my-2"
              >
                {trimmed.replace("> ", "")}
              </blockquote>
            );
          }
          if (trimmed === "") {
            return <div key={idx} className="h-1" />;
          }

          return <p key={idx} dangerouslySetInnerHTML={{ __html: formatBoldText(line) }} />;
        })}
      </div>
    );
  };

  const getStepStatus = (stepKey: string) => {
    const stepsOrder = ["planning", "researching", "analyzing", "verifying", "synthesizing"];

    if (stepKey === "verifying") {
      if (currentStep === "verifying_failed") return "failed";
      if (currentStep === "verifying_passed") return "completed";
    }

    if (currentStep === stepKey) return "active";

    const currentIndex = stepsOrder.indexOf(currentStep.replace("_passed", "").replace("_failed", ""));
    const targetIndex = stepsOrder.indexOf(stepKey);

    if (currentIndex > targetIndex) return "completed";
    if (verdict) return "completed";

    return "idle";
  };

  return (
    <main className="min-h-screen py-10 px-4 md:px-8 max-w-7xl mx-auto flex flex-col justify-between">
      {/* Header */}
      <header className="text-center mb-8 flex flex-col items-center">
        <div className="flex items-center space-x-3 mb-2 animate-float">
          <div className="relative p-3 bg-gradient-to-br from-cyan-500 to-indigo-600 rounded-2xl shadow-lg glow-cyan border border-cyan-400/20">
            <Layers className="h-8 w-8 text-white" />
          </div>
          <h1 className="text-3xl font-extrabold tracking-tight bg-gradient-to-r from-white via-slate-200 to-cyan-400 bg-clip-text text-transparent">
            AntiGravity AI
          </h1>
        </div>
        <p className="text-slate-400 text-sm max-w-md">
          Deep-Dive Financial Research Agent Powered by LangGraph & SQLite Persistence.
        </p>

        {/* Global Connection Badges */}
        <div className="flex space-x-2.5 mt-3">
          <div className="flex items-center space-x-1.5 px-2.5 py-1 bg-slate-900/60 border border-slate-800 text-[10px] text-slate-400 rounded-full font-mono font-medium">
            <div className={`h-1.5 w-1.5 rounded-full ${demo ? "bg-amber-450 animate-pulse" : "bg-emerald-500"}`} />
            <span>{demo ? "Simulated API (Demo)" : "Live API Execution"}</span>
          </div>
          <div className="flex items-center space-x-1.5 px-2.5 py-1 bg-slate-900/60 border border-slate-800 text-[10px] text-slate-450 rounded-full font-mono font-medium">
            <div className="h-1.5 w-1.5 rounded-full bg-emerald-500" />
            <span>SQLite Connected</span>
          </div>
        </div>
      </header>

      {/* Grid containing Inputs + Sidebar & Outputs */}
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Left Side: Strategy Profiler, Inputs & History Sidebar */}
        <div className="lg:col-span-1 space-y-6">
          {/* Main Inputs & Strategy Form */}
          <div className="glass-panel rounded-2xl p-5 border border-white/5 space-y-5">
            <h2 className="text-sm font-semibold text-slate-350 tracking-wider uppercase flex items-center space-x-2 border-b border-white/5 pb-2">
              <SlidersHorizontal className="h-4 w-4 text-cyan-400" />
              <span>Strategy Profiler</span>
            </h2>

            <form onSubmit={handleLaunchAgent} className="space-y-4">
              {/* Ticker Input */}
              <div className="flex flex-col space-y-1">
                <label htmlFor="ticker" className="text-[10px] font-bold text-slate-400 uppercase">
                  Ticker Symbol *
                </label>
                <div className="relative">
                  <Search className="absolute left-3 top-3 h-4 w-4 text-slate-550" />
                  <input
                    id="ticker"
                    type="text"
                    placeholder="e.g. NVDA, AAPL"
                    required
                    value={ticker}
                    onChange={(e) => setTicker(e.target.value)}
                    className="w-full pl-9 pr-3 py-2 bg-slate-950/80 border border-slate-800 rounded-xl text-white placeholder-slate-655 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 text-xs font-semibold uppercase"
                  />
                </div>
              </div>

              {/* Company Name Input */}
              <div className="flex flex-col space-y-1">
                <label htmlFor="companyName" className="text-[10px] font-bold text-slate-400 uppercase">
                  Company Name
                </label>
                <input
                  id="companyName"
                  type="text"
                  placeholder="Optional Name"
                  value={companyName}
                  onChange={(e) => setCompanyName(e.target.value)}
                  className="w-full px-3 py-2 bg-slate-950/80 border border-slate-800 rounded-xl text-white placeholder-slate-655 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 text-xs font-medium"
                />
              </div>

              {/* Investment Horizon */}
              <div className="flex flex-col space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase">Horizon</label>
                <div className="grid grid-cols-3 gap-1 bg-slate-950 p-1 border border-slate-850 rounded-xl">
                  {["Short-Term", "Medium-Term", "Long-Term"].map((hz) => (
                    <button
                      key={hz}
                      type="button"
                      onClick={() => setStrategyHorizon(hz)}
                      className={`py-1 text-[9px] font-bold rounded-lg cursor-pointer transition-all ${
                        strategyHorizon === hz
                          ? "bg-cyan-550 text-slate-950 font-black shadow"
                          : "text-slate-400 hover:text-slate-200"
                      }`}
                    >
                      {hz.split("-")[0]}
                    </button>
                  ))}
                </div>
              </div>

              {/* Risk Profile */}
              <div className="flex flex-col space-y-1.5">
                <label className="text-[10px] font-bold text-slate-400 uppercase">Risk Profile</label>
                <div className="grid grid-cols-3 gap-1 bg-slate-950 p-1 border border-slate-850 rounded-xl">
                  {["Conservative", "Balanced", "Aggressive"].map((rk) => (
                    <button
                      key={rk}
                      type="button"
                      onClick={() => setStrategyRisk(rk)}
                      className={`py-1 text-[9px] font-bold rounded-lg cursor-pointer transition-all ${
                        strategyRisk === rk
                          ? "bg-cyan-550 text-slate-950 font-black shadow"
                          : "text-slate-400 hover:text-slate-200"
                      }`}
                    >
                      {rk.substring(0, 4)}..
                    </button>
                  ))}
                </div>
              </div>

              {/* Weight Adjustment Sliders */}
              <div className="space-y-2.5 pt-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase flex justify-between">
                  <span>Pillar Weights</span>
                  <span className="text-cyan-400 font-mono text-[9px]">Sum: 100%</span>
                </label>

                {/* Slider 1: Revenue Weight */}
                <div className="space-y-1">
                  <div className="flex justify-between text-[9px] text-slate-400 font-medium">
                    <span>Revenue & Growth</span>
                    <span className="font-mono text-cyan-400">{revenueWeight}%</span>
                  </div>
                  <input
                    type="range"
                    min="10"
                    max="80"
                    value={revenueWeight}
                    onChange={(e) => handleWeightChange("revenue", Number(e.target.value))}
                    className="w-full h-1 bg-slate-950 rounded-lg appearance-none cursor-pointer accent-cyan-500"
                  />
                </div>

                {/* Slider 2: Risk Weight */}
                <div className="space-y-1">
                  <div className="flex justify-between text-[9px] text-slate-400 font-medium">
                    <span>SEC Risk Audit</span>
                    <span className="font-mono text-cyan-400">{riskWeight}%</span>
                  </div>
                  <input
                    type="range"
                    min="10"
                    max="80"
                    value={riskWeight}
                    onChange={(e) => handleWeightChange("risk", Number(e.target.value))}
                    className="w-full h-1 bg-slate-950 rounded-lg appearance-none cursor-pointer accent-cyan-500"
                  />
                </div>

                {/* Slider 3: Sentiment Weight */}
                <div className="space-y-1">
                  <div className="flex justify-between text-[9px] text-slate-400 font-medium">
                    <span>Competitor Sentiment</span>
                    <span className="font-mono text-cyan-400">{sentimentWeight}%</span>
                  </div>
                  <input
                    type="range"
                    min="10"
                    max="80"
                    value={sentimentWeight}
                    onChange={(e) => handleWeightChange("sentiment", Number(e.target.value))}
                    className="w-full h-1 bg-slate-950 rounded-lg appearance-none cursor-pointer accent-cyan-500"
                  />
                </div>
              </div>

              {/* Demo Mode & Action Button */}
              <div className="pt-2 space-y-2 border-t border-white/5">
                <div className="flex items-center space-x-2 bg-slate-950/80 border border-slate-850 p-2 rounded-xl">
                  <input
                    id="demo-toggle"
                    type="checkbox"
                    checked={demo}
                    onChange={(e) => setDemo(e.target.checked)}
                    className="h-3.5 w-3.5 rounded border-slate-850 bg-slate-950 text-cyan-500 focus:ring-cyan-500 cursor-pointer accent-cyan-500"
                  />
                  <label htmlFor="demo-toggle" className="text-[10px] font-bold text-slate-450 cursor-pointer select-none">
                    Demo Mode (Simulation)
                  </label>
                </div>

                <button
                  type="submit"
                  disabled={loading || !ticker}
                  className={`w-full py-2.5 bg-gradient-to-r from-cyan-500 to-indigo-600 hover:from-cyan-400 hover:to-indigo-500 text-white font-bold rounded-xl text-xs transition-all shadow-md cursor-pointer flex items-center justify-center space-x-1.5 ${
                    loading ? "opacity-60 cursor-not-allowed" : "hover:-translate-y-0.5"
                  }`}
                >
                  {loading ? (
                    <>
                      <RefreshCw className="h-3.5 w-3.5 animate-spin" />
                      <span>Running Research...</span>
                    </>
                  ) : (
                    <>
                      <Sparkles className="h-3.5 w-3.5" />
                      <span>Initiate Research Loop</span>
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>

          {/* Past Audits History Sidebar */}
          <div className="glass-panel rounded-2xl p-5 border border-white/5 flex flex-col max-h-[300px]">
            <h2 className="text-sm font-semibold text-slate-350 tracking-wider uppercase mb-3 flex items-center space-x-2 border-b border-white/5 pb-2">
              <History className="h-4 w-4 text-indigo-400" />
              <span>Recent Audits ({pastReports.length})</span>
            </h2>
            <div className="flex-1 overflow-y-auto space-y-1.5 pr-1.5">
