                <div className="text-[10px] text-slate-600 text-center py-6">No audits saved in SQLite.</div>
              )}
            </div>
          </div>
        </div>

        {/* Right Side: Graph Pipeline, Logs & Main Verdict Tab Panels */}
        <div className="lg:col-span-3 space-y-6">
          {/* Main Verdict & Safety Score Header Card */}
          {verdict && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {/* Verdict Showcase */}
              <div
                className={`md:col-span-2 glass-panel rounded-2xl p-6 border relative overflow-hidden transition-all duration-500 flex flex-col justify-between ${
                  verdict === "Bullish"
                    ? "border-emerald-500/20 glow-emerald bg-emerald-950/5"
                    : verdict === "Bearish"
                    ? "border-rose-500/20 glow-rose bg-rose-950/5"
                    : "border-amber-500/20 glow-amber bg-amber-950/5"
