                  </div>
                </div>

                {/* Node 4: Validator (Check-Validate Loop) */}
                <div className="relative flex items-start space-x-2.5">
                  <div
                    className={`absolute -left-[20px] h-[10px] w-[10px] rounded-full border-2 ${
