                </div>
              </div>
            </div>

            {/* Console Log Panel */}
            <div className="md:col-span-2 glass-panel rounded-2xl p-5 border border-white/5 flex flex-col h-[230px]">
              <h2 className="text-sm font-semibold text-slate-350 tracking-wider uppercase mb-3 flex items-center space-x-2">
                <div className={`h-2 w-2 rounded-full bg-cyan-400 ${loading ? "pulse-dot-cyan" : ""}`} />
                <span>Agent Logs</span>
              </h2>
              <div className="flex-1 bg-slate-950/90 border border-slate-900/80 rounded-xl p-3 font-mono text-[10px] text-slate-400 overflow-y-auto space-y-1 leading-relaxed">
                {logs.map((log, index) => (
                  <div key={index} className="whitespace-pre-wrap">
                    <span className="text-slate-650 mr-1">&gt;</span>
                    {log}
                  </div>
                ))}
                {loading && (
                  <div className="flex items-center space-x-1.5 text-cyan-400 animate-pulse mt-1">
