              )}

              {!verdict && !loading && (
                <div className="h-full flex flex-col items-center justify-center text-center text-slate-500 py-16">
                  <Layers className="h-12 w-12 text-slate-700 mb-3 animate-pulse" />
                  <h3 className="text-sm font-semibold text-slate-400">Awaiting Agent Input</h3>
                  <p className="text-xs text-slate-605 max-w-xs mt-1">
                    Configure your investment strategy profiles in the sidebar and click launch.
                  </p>
                </div>
              )}

              {!verdict && loading && (
                <div className="h-full flex flex-col items-center justify-center text-center text-slate-405 py-16 space-y-4">
                  <RefreshCw className="h-10 w-10 text-cyan-400 animate-spin" />
                  <div>
                    <h3 className="text-sm font-semibold text-slate-300">
                      {currentStep === "planning"
                        ? "Planning queries..."
                        : currentStep === "researching"
                        ? "Querying Tavily AI..."
                        : currentStep === "analyzing"
                        ? "Reasoning and analyzing..."
                        : currentStep.startsWith("verifying")
                        ? "Running fact-check validation..."
                        : currentStep === "synthesizing"
                        ? "Synthesizing and running Python scoring..."
                        : "Initializing agent loops..."}
                    </h3>
                    <p className="text-xs text-slate-500 mt-1">
                      Executing LangGraph cyclic state machine.
                    </p>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </main>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { getChatModel } from "@/lib/tools";

export async function POST(req: NextRequest) {
  try {
    const { companyInput } = await req.json();

    if (!companyInput) {
      return NextResponse.json({ error: "Company input is required" }, { status: 400 });
    }

    // Mock fallback configurations if no API keys are present (for clean offline demo experience)
    if (!process.env.OPENAI_API_KEY && !process.env.GEMINI_API_KEY && !process.env.ANTHROPIC_API_KEY) {
      const inputUpper = companyInput.toUpperCase();
      let config = {
        horizon: "Long",
        riskProfile: "Balanced",
        weights: {
          revenueAndGrowth: 40,
          secRiskAudit: 30,
          competitorSentiment: 30,
        },
        rationale: `Standard balanced profile generated for ${companyInput} based on sector metrics.`,
      };

      if (inputUpper.includes("NVDA") || inputUpper.includes("NVIDIA")) {
        config = {
          horizon: "Long",
          riskProfile: "Aggressive",
          weights: {
            revenueAndGrowth: 50,
            secRiskAudit: 15,
            competitorSentiment: 35,
          },
          rationale: "NVIDIA's massive growth curves and active competitor narratives require highly growth-oriented auditing.",
        };
      } else if (inputUpper.includes("TSLA") || inputUpper.includes("TESLA")) {
        config = {
          horizon: "Long",
          riskProfile: "Aggressive",
          weights: {
            revenueAndGrowth: 45,
            secRiskAudit: 20,
            competitorSentiment: 35,
          },
          rationale: "Tesla operates with volatile margins and significant geopolitical supply chain regulatory dependencies.",
        };
      } else if (inputUpper.includes("AAPL") || inputUpper.includes("APPLE")) {
        config = {
          horizon: "Long",
          riskProfile: "Conservative",
          weights: {
            revenueAndGrowth: 35,
            secRiskAudit: 40,
            competitorSentiment: 25,
          },
          rationale: "Apple is a mature capital return leader where cash preservation, litigation, and stable margins take precedence.",
        };
      }

      return NextResponse.json(config);
    }

    const model = getChatModel();
    const prompt = `You are an expert financial strategist and quantitative analyst configuring an AI investment research agent. 
Your task is to evaluate the provided company and define the optimal research parameters based on its sector, market maturity, and current macroeconomic dynamics.

Target Company / Ticker: ${companyInput}

You must output your configuration as a strict JSON object with the following schema. Do not include markdown formatting, backticks, or any conversational text.
{
  "horizon": "Short" | "Long" | "Medium",
  "riskProfile": "Conservative" | "Balanced" | "Aggressive",
  "weights": {
    "revenueAndGrowth": <integer 0-100>,
    "secRiskAudit": <integer 0-100>,
    "competitorSentiment": <integer 0-100>
  },
  "rationale": "A one-sentence explanation of why these settings are optimal for this specific company"
}

Constraints:
1. The three values inside "weights" MUST sum exactly to 100.
2. Tailor the weights to the company's nature (e.g., A volatile tech startup requires high Competitor Sentiment and Revenue weight. A legacy bank or highly regulated utility requires high SEC Risk Audit weight).
3. Output ONLY valid JSON.`;

    const response = await model.invoke(prompt);
    const content = response.content as string;

    const jsonStart = content.indexOf("{");
    const jsonEnd = content.lastIndexOf("}");
    if (jsonStart === -1 || jsonEnd === -1) {
      throw new Error("Model failed to return structured parameters.");
    }

    const config = JSON.parse(content.substring(jsonStart, jsonEnd + 1));
    return NextResponse.json(config);
  } catch (error: any) {
    console.error("Auto-tune API error:", error);
    return NextResponse.json(
      { error: error.message || "Failed to analyze optimal parameters." },
      { status: 550 }
    );
  }
}

