  }),
  sentimentCompetitorsAnalysis: Annotation<string>({
    reducer: (x, y) => y,
    default: () => "",
  }),
  verificationLog: Annotation<string[]>({
    reducer: (x, y) => x.concat(y),
    default: () => [],
  }),
  verificationPassed: Annotation<boolean>({
    reducer: (x, y) => y,
    default: () => false,
  }),
  verdict: Annotation<"Bullish" | "Bearish" | "Neutral" | null>({
