import { NextRequest, NextResponse } from "next/server";
import { getChatModel } from "@/lib/tools";

export async function POST(req: NextRequest) {
  try {
    const { companyInput, modelProvider } = await req.json();

    if (!companyInput) {
      return NextResponse.json({ error: "Company input is required" }, { status: 400 });
    }

    if (!process.env.OPENAI_API_KEY && !process.env.GEMINI_API_KEY && !process.env.ANTHROPIC_API_KEY) {
      return NextResponse.json(
        { error: "No LLM API keys are configured in your `.env.local` file." },
        { status: 500 }
      );
    }

    const model = getChatModel(modelProvider);
    const prompt = `You are an expert financial strategist and quantitative analyst configuring an AI investment research agent. 
Your task is to evaluate the provided company and define the optimal research parameters based on its sector, market maturity, and current macroeconomic dynamics.

Target Company / Ticker: ${companyInput}

You must output your configuration as a strict JSON object with the following schema. Do not include markdown formatting, backticks, or any conversational text.
{
  "horizon": "Short" | "Long" | "Medium",
  "riskProfile": "Conservative" | "Balanced" | "Aggressive",
  "weights": {
    "revenueAndGrowth": <integer 0-100>,
    "secRiskAudit": <integer 0-100>,
    "competitorSentiment": <integer 0-100>
  },
  "rationale": "A one-sentence explanation of why these settings are optimal for this specific company"
}

Constraints:
1. The three values inside "weights" MUST sum exactly to 100.
2. Tailor the weights to the company's nature (e.g., A volatile tech startup requires high Competitor Sentiment and Revenue weight. A legacy bank or highly regulated utility requires high SEC Risk Audit weight).
3. Output ONLY valid JSON.`;

    const response = await model.invoke(prompt);
    const content = response.content as string;

    const jsonStart = content.indexOf("{");
    const jsonEnd = content.lastIndexOf("}");
    if (jsonStart === -1 || jsonEnd === -1) {
      throw new Error("Model failed to return structured parameters.");
    }

    const config = JSON.parse(content.substring(jsonStart, jsonEnd + 1));
    return NextResponse.json(config);
  } catch (error: any) {
    console.error("Auto-tune API error:", error);
    return NextResponse.json(
      { error: error.message || "Failed to analyze optimal parameters." },
      { status: 550 }
    );
  }
}

import { NextRequest } from "next/server";
import { agent } from "@/lib/agent";
import { PrismaClient } from "@prisma/client";

export const runtime = "nodejs";

const prisma = new PrismaClient();

// GET past reports from database
export async function GET() {
  try {
    const reports = await prisma.researchReport.findMany({
      orderBy: { createdAt: "desc" },
      take: 20,
    });
    return new Response(JSON.stringify(reports), {
      headers: { "Content-Type": "application/json" },
    });
  } catch (error: any) {
    console.error("Failed to fetch reports:", error);
    return new Response(JSON.stringify({ error: error.message }), {
      status: 550,
      headers: { "Content-Type": "application/json" },
    });
  }
}

// POST run research agent loop
export async function POST(req: NextRequest) {
  try {
    const {
      ticker,
      companyName,
      modelProvider,
      strategyHorizon,
      strategyRisk,
      revenueWeight,
      riskWeight,
      sentimentWeight,
    } = await req.json();

    if (!ticker) {
      return new Response(JSON.stringify({ error: "Ticker symbol is required" }), {
        status: 400,
        headers: { "Content-Type": "application/json" },
      });
    }

    // Check for required API keys
    if (!process.env.TAVILY_API_KEY) {
      return new Response(
        JSON.stringify({
          error: "TAVILY_API_KEY is not configured in `.env.local`. Please configure it to enable web research.",
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    if (!process.env.OPENAI_API_KEY && !process.env.GEMINI_API_KEY && !process.env.ANTHROPIC_API_KEY) {
      return new Response(
        JSON.stringify({
          error: "No LLM API Key (OPENAI_API_KEY, ANTHROPIC_API_KEY, or GEMINI_API_KEY) is configured in `.env.local`. Please provide one to enable LLM reasoning.",
        }),
        {
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    const encoder = new TextEncoder();
    const stream = new ReadableStream({
      async start(controller) {
        try {
          const agentStream = await agent.stream(
            {
              ticker: ticker.toUpperCase().trim(),
              companyName: companyName ? companyName.trim() : "",
              modelProvider: modelProvider || "gemini",
              strategyHorizon: strategyHorizon || "Medium-Term",
              strategyRisk: strategyRisk || "Balanced",
              revenueWeight: Number(revenueWeight) || 33.3,
              riskWeight: Number(riskWeight) || 33.3,
              sentimentWeight: Number(sentimentWeight) || 33.4,
            },
            {
              streamMode: "values",
            }
          );

          let finalChunk: any = null;

          for await (const chunk of agentStream) {
            finalChunk = chunk;
            const data = {
              currentStep: chunk.currentStep,
              logs: chunk.logs || [],
              queries: chunk.queries || [],
              verdict: chunk.verdict,
              safetyScore: chunk.safetyScore || 0,
              safetyBreakdown: chunk.safetyBreakdown || "{}",
              reasoningReport: chunk.reasoningReport,
              revenueGrowthAnalysis: chunk.revenueGrowthAnalysis,
              risksAnalysis: chunk.risksAnalysis,
              sentimentCompetitorsAnalysis: chunk.sentimentCompetitorsAnalysis,
              retryCount: chunk.retryCount || 0,
              verificationLog: chunk.verificationLog || [],
              verificationPassed: chunk.verificationPassed || false,
            };

            controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
          }

          // Persist successfully completed reports to the database
          if (finalChunk && finalChunk.verdict && finalChunk.currentStep === "synthesizing") {
            try {
              await prisma.researchReport.create({
                data: {
                  ticker: ticker.toUpperCase().trim(),
                  companyName: finalChunk.companyName || companyName || ticker.toUpperCase().trim(),
                  verdict: finalChunk.verdict,
                  safetyScore: finalChunk.safetyScore || 0,
                  reasoningReport: finalChunk.reasoningReport || "",
                  revenueAnalysis: finalChunk.revenueGrowthAnalysis || "",
                  risksAnalysis: finalChunk.risksAnalysis || "",
                  sentimentAnalysis: finalChunk.sentimentCompetitorsAnalysis || "",
                  strategyHorizon: strategyHorizon || "Medium-Term",
                  strategyRisk: strategyRisk || "Balanced",
                },
              });
            } catch (dbErr) {
              console.error("Database save failed:", dbErr);
            }
          }

          controller.close();
        } catch (err: any) {
          console.error("Agent Streaming Error:", err);
          controller.enqueue(
            encoder.encode(
              `data: ${JSON.stringify({
                error: err.message || "An unexpected error occurred during research loop",
              })}\n\n`
            )
          );
          controller.close();
        }
      },
    });

    return new Response(stream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache, no-transform",
        "Connection": "keep-alive",
      },
    });
  } catch (error: any) {
    console.error("API Route Error:", error);
    return new Response(JSON.stringify({ error: error.message || "Invalid request body" }), {
      status: 400,
      headers: { "Content-Type": "application/json" },
    });
  }
}

