371:   const handleLaunchAgent = async (e: React.FormEvent) => {
372:     e.preventDefault();
373:     if (!ticker) return;
374: 
375:     // Reset previous state
376:     setLoading(true);
377:     setError(null);
378:     setCurrentStep("initiating");
379:     setLogs(["Launching AntiGravity Investment Agent...", "Awaiting LangGraph State Machine initialization..."]);
380:     setQueries([]);
381:     setVerdict(null);
382:     setSafetyScore(0);
383:     setSafetyBreakdown({});
384:     setReasoningReport("");
385:     setRevenueGrowth("");
386:     setRisks("");
387:     setSentiment("");
388:     setRetryCount(0);
389:     setVerificationLog([]);
390:     setVerificationPassed(false);
391: 
392:     try {
393:       const response = await fetch("/api/research", {
394:         method: "POST",
395:         headers: {
396:           "Content-Type": "application/json",
397:         },
398:         body: JSON.stringify({
399:           ticker: ticker.toUpperCase(),
400:           companyName,
401:           modelProvider,
402:           strategyHorizon,
403:           strategyRisk,
404:           revenueWeight,
405:           riskWeight,
406:           sentimentWeight,
407:         }),
408:       });
409: 
410:       if (!response.ok) {
411:         const errorData = await response.json();
412:         throw new Error(errorData.error || "Failed to initiate research agent");
413:       }
414: 
415:       const reader = response.body?.getReader();
416:       const decoder = new TextDecoder();
417: 
418:       if (!reader) {
419:         throw new Error("Failed to read server response stream");
420:       }
421: 
422:       let buffer = "";
423: 
424:       while (true) {
425:         const { done, value } = await reader.read();
426:         if (done) break;
427: 
428:         buffer += decoder.decode(value, { stream: true });
429:         const lines = buffer.split("\n\n");
430:         buffer = lines.pop() || "";
431: 
432:         for (const line of lines) {
433:           if (line.startsWith("data: ")) {
434:             const jsonStr = line.substring(6);
435:             try {
436:               const data = JSON.parse(jsonStr) as StreamData;
437: 
438:               if (data.error) {
439:                 setError(data.error);
440:                 setLogs((prev) => [...prev, `❌ Error: ${data.error}`]);
441:                 setLoading(false);
442:                 return;
443:               }
444: 
445:               if (data.currentStep) setCurrentStep(data.currentStep);
446:               if (data.retryCount !== undefined) setRetryCount(data.retryCount);
447:               if (data.verificationPassed !== undefined) setVerificationPassed(data.verificationPassed);
448: 
449:               if (data.logs && data.logs.length > 0) {
450:                 setLogs(data.logs);
451:               }
452:               if (data.queries && data.queries.length > 0) {
453:                 setQueries(data.queries);
454:               }
455:               if (data.verificationLog && data.verificationLog.length > 0) {
456:                 setVerificationLog(data.verificationLog);
457:               }
458: 
459:               if (data.revenueGrowthAnalysis) setRevenueGrowth(data.revenueGrowthAnalysis);
460:               if (data.risksAnalysis) setRisks(data.risksAnalysis);
461:               if (data.sentimentCompetitorsAnalysis) setSentiment(data.sentimentCompetitorsAnalysis);
462:               if (data.verdict) setVerdict(data.verdict);
463:               if (data.safetyScore) setSafetyScore(data.safetyScore);
464:               if (data.safetyBreakdown) {
465:                 try {
466:                   setSafetyBreakdown(JSON.parse(data.safetyBreakdown));
467:                 } catch {
