import { NextResponse } from "next/server";
import { prisma } from "@/lib/db";

export async function POST(req: Request) {
  try {
    const { name, email, password } = await req.json();

    if (!name || !email || !password) {
      return NextResponse.json(
        { error: "Name, email, and password are required." },
        { status: 400 }
      );
    }

    // Check if user already exists
    const existingUser = await prisma.user.findUnique({
      where: { email },
    });

    if (existingUser) {
      return NextResponse.json(
        { error: "A user with this email already exists." },
        { status: 400 }
      );
    }

    // Create user in database
    const user = await prisma.user.create({
      data: {
        name,
        email,
        password, // stored directly for SQLite demo sandbox
        role: "Senior Quant Analyst",
      },
    });

    return NextResponse.json({
      message: "User registered successfully.",
      user: {
        id: user.id,
        name: user.name,
        email: user.email,
        role: user.role,
      },
    });
  } catch (error: any) {
    console.error("Signup error:", error);
    return NextResponse.json(
      { error: error.message || "Failed to register user." },
      { status: 500 }
    );
  }
}

"use client";

import React, { useState } from "react";
import { useRouter } from "next/navigation";
import { Layers, ArrowLeft, Loader2, Sparkles } from "lucide-react";

export default function SignupPage() {
  const router = useRouter();
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !email || !password) {
      setError("Please fill in all fields.");
      return;
    }

    setError(null);
    setLoading(true);

    try {
      const res = await fetch("/api/auth/signup", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ name, email, password }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || "Failed to create account.");
      }

      // Store registered user session in local storage
      localStorage.setItem("antigravity_user", JSON.stringify(data.user));

      setSuccess(true);
      setTimeout(() => {
        router.push("/terminal");
      }, 1500);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center px-4 relative overflow-hidden font-sans">
      {/* Ambient glows */}
      <div className="absolute top-1/4 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] bg-blue-600/10 rounded-full blur-[140px] pointer-events-none" />
      <div className="absolute bottom-1/4 left-1/3 w-[400px] h-[400px] bg-cyan-500/10 rounded-full blur-[140px] pointer-events-none" />

      {/* Back button */}
      <button
        onClick={() => router.push("/")}
        className="absolute top-6 left-6 flex items-center space-x-2 text-xs font-semibold text-slate-450 hover:text-white cursor-pointer transition-colors bg-slate-900/60 border border-slate-850 px-3.5 py-2 rounded-xl"
      >
        <ArrowLeft className="h-4 w-4" />
        <span>Back to Storefront</span>
      </button>

      <div className="max-w-md w-full z-10 space-y-6">
        {/* Logo Header */}
        <div className="flex flex-col items-center space-y-3.5 text-center">
          <div className="p-3 bg-gradient-to-br from-blue-600 to-cyan-500 rounded-2xl shadow-xl border border-white/10">
            <Layers className="h-6 w-6 text-white" />
          </div>
          <h1 className="text-2xl font-black text-white tracking-tight">Create Strategist Account</h1>
          <p className="text-slate-400 text-xs max-w-[32ch]">
            Register in the persistent SQLite node to save default strategies and customized research profiles.
          </p>
        </div>

        {/* Card Form */}
        <div className="bg-slate-900/40 backdrop-blur-xl border border-slate-850 rounded-3xl p-6 md:p-8 space-y-5 shadow-2xl relative">
          <div className="absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-0.5 bg-slate-950 border border-white/5 rounded-full text-[8px] font-bold text-slate-500 uppercase tracking-widest">
            Registration Node
          </div>

          {success ? (
            <div className="text-center py-8 space-y-3.5 animate-pulse">
              <div className="inline-flex p-3 bg-emerald-950/40 border border-emerald-900/40 rounded-full text-emerald-400">
                <Sparkles className="h-6 w-6" />
              </div>
              <div>
                <p className="text-sm font-bold text-white">Account Created Successfully!</p>
                <p className="text-[10px] text-slate-450 mt-1">Provisioning research sandbox keys...</p>
              </div>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-4">
              {error && (
                <div className="p-3 bg-rose-955/20 border border-rose-900/30 text-rose-455 text-[10px] font-semibold rounded-xl text-center leading-relaxed">
                  {error}
                </div>
              )}

              {/* Full Name */}
              <div className="flex flex-col space-y-1">
                <label className="text-[10px] font-bold text-slate-455 uppercase tracking-wide">
                  Full Name
                </label>
                <input
                  type="text"
                  placeholder="e.g. Alex Miller"
                  value={name}
                  onChange={(e) => {
                    setName(e.target.value);
                    setError(null);
                  }}
                  required
                  className="w-full px-3 py-2 bg-slate-955/80 border border-slate-800 rounded-xl text-xs font-semibold text-white placeholder-slate-655 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500"
                />
              </div>

              {/* Email Address */}
              <div className="flex flex-col space-y-1">
                <label className="text-[10px] font-bold text-slate-455 uppercase tracking-wide">
                  Email Address
                </label>
                <input
                  type="email"
                  placeholder="alex.miller@portfolio.com"
                  value={email}
                  onChange={(e) => {
                    setEmail(e.target.value);
                    setError(null);
                  }}
                  required
                  className="w-full px-3 py-2 bg-slate-955/80 border border-slate-800 rounded-xl text-xs font-semibold text-white placeholder-slate-655 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500"
                />
              </div>

              {/* Password */}
              <div className="flex flex-col space-y-1">
                <label className="text-[10px] font-bold text-slate-455 uppercase tracking-wide">
                  Password
                </label>
                <input
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => {
                    setPassword(e.target.value);
                    setError(null);
                  }}
                  required
                  className="w-full px-3 py-2 bg-slate-955/80 border border-slate-800 rounded-xl text-xs font-semibold text-white placeholder-slate-655 focus:outline-none focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500"
                />
              </div>

              {/* Submit Button */}
              <div className="pt-2">
                <button
                  type="submit"
                  disabled={loading}
                  className="w-full py-3 bg-gradient-to-r from-blue-600 to-cyan-500 hover:from-blue-500 hover:to-cyan-400 text-white font-extrabold rounded-xl text-xs tracking-wider uppercase transition-all shadow-md active:scale-97 cursor-pointer flex items-center justify-center space-x-1.5 disabled:opacity-60 disabled:cursor-not-allowed border border-white/5"
                >
                  {loading ? (
                    <>
                      <Loader2 className="h-4 w-4 animate-spin text-white" />
                      <span>Creating Account...</span>
                    </>
                  ) : (
                    <span>Register Account</span>
                  )}
                </button>
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}

