@import "tailwindcss";

@theme {
  --color-background-dark: #f7f8fa;
  --color-panel-dark: rgba(255, 255, 255, 0.75);
  --color-cyan-glow: rgba(37, 99, 235, 0.08);
  --color-rose-glow: rgba(244, 63, 94, 0.08);
  --color-emerald-glow: rgba(16, 185, 129, 0.08);

  --animate-float: float 6s ease-in-out infinite;
  --animate-pulse-fast: pulse-fast 1.5s cubic-bezier(0.4, 0, 0.6, 1) infinite;
  --animate-glow: glow 2s ease-in-out infinite alternate;

  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-10px); }
  }
  @keyframes pulse-fast {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: .4; transform: scale(0.95); }
  }
  @keyframes glow {
    from {
      text-shadow: 0 0 4px rgba(37, 99, 235, 0.15), 0 0 10px rgba(37, 99, 235, 0.05);
    }
    to {
      text-shadow: 0 0 8px rgba(37, 99, 235, 0.25), 0 0 20px rgba(37, 99, 235, 0.15);
    }
  }
}

:root {
  --background: #f7f8fa;
  --foreground: #14172b;
}

body {
  background-color: var(--background);
  color: var(--foreground);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  overflow-x: hidden;
  background-image: 
    radial-gradient(at 0% 0%, rgba(37, 99, 235, 0.04) 0px, transparent 50%),
    radial-gradient(at 100% 100%, rgba(56, 189, 248, 0.04) 0px, transparent 50%),
    radial-gradient(at 50% 0%, rgba(244, 63, 94, 0.01) 0px, transparent 50%);
  background-attachment: fixed;
}

/* Glassmorphism custom styling for light mode */
.glass-panel {
  background: rgba(255, 255, 255, 0.75);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(0, 0, 0, 0.06);
}

.glass-panel-hover {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.glass-panel-hover:hover {
  background: rgba(255, 255, 255, 0.9);
  border-color: rgba(37, 99, 235, 0.2);
  box-shadow: 0 10px 30px -10px rgba(37, 99, 235, 0.08);
  transform: translateY(-2px);
}

/* Custom glow effect */
.glow-cyan {
  box-shadow: 0 0 20px 0 rgba(37, 99, 235, 0.08);
}

.glow-emerald {
  box-shadow: 0 0 25px 0 rgba(16, 185, 129, 0.1);
}

.glow-rose {
  box-shadow: 0 0 25px 0 rgba(244, 63, 94, 0.1);
}

.glow-amber {
  box-shadow: 0 0 25px 0 rgba(245, 158, 11, 0.1);
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: rgba(238, 240, 244, 0.6);
}

::-webkit-scrollbar-thumb {
  background: rgba(0, 0, 0, 0.08);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(37, 99, 235, 0.25);
}

/* Markdown styling for reports in light mode */
.prose-report h1, .prose-report h2, .prose-report h3 {
  color: #14172b;
  font-weight: 700;
  margin-top: 1.5rem;
  margin-bottom: 0.75rem;
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);
  padding-bottom: 0.25rem;
}

.prose-report h1 { font-size: 1.5rem; }
.prose-report h2 { font-size: 1.25rem; }
.prose-report h3 { font-size: 1.1rem; }

.prose-report p {
  color: #565b74;
  line-height: 1.625;
  margin-bottom: 1rem;
}

.prose-report ul, .prose-report ol {
  margin-left: 1.25rem;
  margin-bottom: 1rem;
  color: #565b74;
}

.prose-report li {
  margin-bottom: 0.35rem;
  list-style-type: disc;
}

.prose-report strong {
  color: #14172b;
  font-weight: 600;
}

.prose-report blockquote {
  border-left: 3px solid #2563eb;
  padding-left: 1rem;
  margin: 1.5rem 0;
  font-style: italic;
  color: #565b74;
}

/* Real-time logging pulse animation */
@keyframes pulse-ring {
  0% { transform: scale(0.95); opacity: 0.5; }
  50% { transform: scale(1.1); opacity: 0.8; }
  100% { transform: scale(0.95); opacity: 0.5; }
}

.pulse-dot-cyan {
  position: relative;
}
.pulse-dot-cyan::after {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  border-radius: 50%;
  border: 2px solid rgba(37, 99, 235, 0.3);
  animation: pulse-ring 2s infinite ease-in-out;
}

