                key={idx}
                className="text-lg font-black text-[#14172b] tracking-tight border-b border-[#e3e5ed] pb-1.5 mt-5 font-display"
                dangerouslySetInnerHTML={{ __html: formatBoldText(trimmed.substring(2)) }}
              />
