                  <div className="p-1 bg-gradient-to-br from-blue-600 to-cyan-500 rounded-lg">
                    <Layers className="h-4 w-4 text-white" />
                  </div>
                  <span className="font-extrabold text-sm text-[#14172b]">Strategist Deck</span>
                </div>
