                  onClick={() => setDrawerOpen(false)}
                  className="p-1.5 hover:bg-slate-100 border border-[#e3e5ed] rounded-lg text-[#565b74] hover:text-[#14172b]"
                >
                  <X className="h-4 w-4" />
                </button>
              </div>

