    return new ChatAnthropic({
      modelName: "claude-3-5-sonnet-latest",
      temperature,
      apiKey: process.env.ANTHROPIC_API_KEY,
    });
  }

  throw new Error("No API keys (GEMINI_API_KEY, OPENAI_API_KEY, or ANTHROPIC_API_KEY) found in env.");
}

